const items = $input.all();
return items.map(item => {
  const json = item.json;
  // N8N OpenAI node (DALL-E) returns the URL in different paths depending on version/settings
  let url = json.url;

  if (!url && json.data && Array.isArray(json.data) && json.data.length > 0) {
    url = json.data[0].url;
  }

  if (!url) {
     // Pass the error explicitly to stop execution smoothly or let the HTTP Request fail differently
     throw new Error('No Cover URL found in DALL-E response. Raw response: ' + JSON.stringify(json));
  }

  return { json: { url: url } };
});

const response = $input.first().json;
let content = "";

if (response && response.choices && response.choices.length > 0 && response.choices[0].message) {
  content = response.choices[0].message.content;
}

const bookData = $node["Prepare Cover Prompt"].json;
let refinedPrompt = bookData.prompt;

if (content) {
  refinedPrompt = content
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .replace(/^[\"']|[\"']$/g, '')
    .replace(/{\"refined_prompt\":\s*\"/g, '')
    .replace(/\"}/g, '')
    .trim();
}

if (!refinedPrompt || refinedPrompt.length < 50) {
  refinedPrompt = bookData.prompt;
}

// Max length validation
if (refinedPrompt.length > 3900) {
  refinedPrompt = refinedPrompt.substring(0, 3900);
}

return {
  json: {
    refinedPrompt,
    bookId: bookData.bookId
  }
};

