// Safely build the OpenAI JSON payload for the Scaffolder.
// Using JS string templates here avoids n8n expression injection bugs
// when chapter titles/summaries contain apostrophes or special chars.
const webhookBody = $('Webhook Router').first().json?.body || {};
const chapterTitle = webhookBody.chapter?.title || 'Capitolo Sconosciuto';
const chapterSummary = webhookBody.chapter?.summary || '';
const feedback = webhookBody.feedback || 'Nessun feedback. Genera da zero.';
const targetCount = webhookBody.targetParagraphCount || 5;

// Extracted materials from RAG (if any)
const ragChunks = $('RAG: Query Scaffold').all().map(item => item.json && item.json.content ? item.json.content : "").filter(x => x).join("  ");

const systemPrompt = `Sei l'Architetto Letterario W4U. Il tuo compito è spezzettare un Capitolo in ESATTAMENTE ${targetCount} Sottocapitoli (chiamati Paragrafi).

IMPORTANTE: RISPONDI SOLO CON UN OGGETTO JSON. NESSUN TESTO INTRODUTTIVO. NON USARE MAI EMOJI.

TITOLO CAPITOLO: ${chapterTitle}
SOMMARIO CAPITOLO: ${chapterSummary}

MATERIALE ESTRAPOLATO DAL MANOSCRITTO (Usa questo come base se presente):
${ragChunks || 'Nessun materiale specifico trovato.'}

FEEDBACK UTENTE (se presente): ${feedback}

ISTRUZIONI:
- Dividi il capitolo in ESATTAMENTE ${targetCount} paragrafi in base al GENERE:
  -- Saggistica/Manuale/Informativo: Introduzione, Argomentazioni Logiche, Dati, Sottocapitoli tematici.
  -- Ricettario: Ingredienti, Strumenti, Step preparazione, Valori.
  -- Narrativa (Romance, SciFi, Thriller): Scene narrative (incidenti scatenanti, plot twist, esplorazione).
- Ogni paragrafo dovrà poi essere usato per generare un blocco di circa 250 parole.
- CRITICAL RULE: DEVI GENERARE ESATTAMENTE ${targetCount} PARAGRAFI. NON UNO DI PIU', NON UNO DI MENO.
- Restituisci un array JSON di queste scene.

Output JSON: { "paragraphs": [ { "paragraph_number": 1, "title": "Titolo Scena...", "description": "Descrizione super dettagliata..." } ] }`;

const openaiPayload = {
    model: 'gpt-4o-mini',
    max_tokens: 4000,
    response_format: { type: 'json_object' },
    messages: [
        { role: 'system', content: systemPrompt }
    ]
};

return { json: openaiPayload };

const text = $node["Webhook Router"].json.body.textContent || "";
